import { tokens } from '../../styles/tokens';

/**
 * GlassPanel - Shared glass morphism container used across all pages.
 *
 * Props:
 *   children   - React children
 *   style      - Additional inline styles (merged, not overridden)
 *   className  - Additional CSS class names
 *   hover      - Enable subtle hover brightness lift (default: false)
 *   glow       - Glow color string, e.g. '#3FB950'. Adds box-shadow glow.
 *   padding    - Override padding (default: tokens.spacing.lg = 16)
 *   noBorder   - Remove border (default: false)
 *   onClick    - Click handler (adds cursor: pointer)
 *   as         - HTML element type (default: 'div')
 */
export default function GlassPanel({
  children,
  style,
  className,
  hover = false,
  glow,
  padding,
  noBorder = false,
  onClick,
  as: Tag = 'div',
  ...rest
}) {
  const pad = padding !== undefined ? padding : tokens.spacing.lg;

  const baseStyle = {
    background: tokens.glass.bg,
    backdropFilter: tokens.glass.blur,
    WebkitBackdropFilter: tokens.glass.blur,
    border: noBorder ? 'none' : `1px solid ${tokens.glass.border}`,
    borderRadius: tokens.radius.lg,
    padding: pad,
    transition: tokens.transition.fast,
    ...(glow ? { boxShadow: tokens.shadow.glow(glow) } : {}),
    ...(onClick ? { cursor: 'pointer' } : {}),
    ...style,
  };

  const handleMouseEnter = hover
    ? (e) => {
        e.currentTarget.style.background = tokens.color.surfaceHover;
        e.currentTarget.style.borderColor = tokens.color.borderHover;
      }
    : undefined;

  const handleMouseLeave = hover
    ? (e) => {
        e.currentTarget.style.background = tokens.glass.bg;
        e.currentTarget.style.borderColor = noBorder ? 'transparent' : tokens.glass.border;
      }
    : undefined;

  return (
    <Tag
      style={baseStyle}
      className={className}
      onClick={onClick}
      onMouseEnter={handleMouseEnter}
      onMouseLeave={handleMouseLeave}
      {...rest}
    >
      {children}
    </Tag>
  );
}
